module RefModule(i_clk, i_rst_n, i_pc, o_pc);input               i_clk, i_rst_n;
input       [31:0]  i_pc;
output  reg [31:0]  o_pc;


	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge i_clk or negedge i_rst_n or posedge dbg_halt)
		begin
			if(!i_rst_n) 
			o_pc <= 0; 
			else
			o_pc <= i_pc;
		end
endmodule
